<script setup lang="ts">
import { CalendarDays, Check, Edit3, Film, Gift, Heart, LoaderCircle, Map, MoreHorizontal, Plus, Trash2, X } from '@lucide/vue'
import type { ListCategory,ListPriority,TogetherItem } from '~/composables/useTogetherList'
const{items,listLoading,loadItems,createItem,updateItem,toggleItem,deleteItem}=useTogetherList();const filter=ref<'all'|ListCategory>('all');const editorOpen=ref(false);const editing=ref<TogetherItem|null>(null);const title=ref('');const note=ref('');const category=ref<ListCategory>('wish');const priority=ref<ListPriority>('normal');const plannedDate=ref('');const busy=ref(false);const error=ref('');const menuId=ref<string|null>(null)
const categories=[{id:'all',label:'全部',icon:Heart},{id:'wish',label:'愿望',icon:Gift},{id:'travel',label:'旅行',icon:Map},{id:'movie',label:'电影',icon:Film},{id:'date',label:'约会',icon:CalendarDays}] as const
const visible=computed(()=>filter.value==='all'?items.value:items.value.filter(x=>x.category===filter.value));const done=computed(()=>items.value.filter(x=>x.completed).length);const progress=computed(()=>items.value.length?Math.round(done.value/items.value.length*100):0)
onMounted(loadItems)
function openCreate(){editing.value=null;title.value='';note.value='';category.value=filter.value==='all'?'wish':filter.value;priority.value='normal';plannedDate.value='';error.value='';editorOpen.value=true}
function openEdit(item:TogetherItem){editing.value=item;title.value=item.title;note.value=item.note;category.value=item.category;priority.value=item.priority;plannedDate.value=item.plannedDate;menuId.value=null;editorOpen.value=true}
async function save(){if(!title.value.trim()){error.value='请输入清单内容';return}busy.value=true;try{const input={title:title.value.trim(),note:note.value.trim(),category:category.value,priority:priority.value,plannedDate:plannedDate.value};editing.value?await updateItem(editing.value.id,input):await createItem(input);editorOpen.value=false}catch(e:any){error.value=e.message}finally{busy.value=false}}
async function remove(item:TogetherItem){if(confirm('确定删除这项共同计划吗？')){try{await deleteItem(item)}catch(e:any){alert(e.message)}}menuId.value=null}
function categoryMeta(id:ListCategory){return categories.find(x=>x.id===id)!}
function formatDate(date:string){if(!date)return'';return new Intl.DateTimeFormat('zh-CN',{month:'short',day:'numeric'}).format(new Date(`${date}T12:00:00`))}
</script>
<template><section class="list-view"><header class="list-header"><div><p class="eyebrow">TOGETHER LIST</p><h1>共同清单</h1><span>把想做的事写下来，然后一件件一起完成。</span></div><button type="button" @click="openCreate"><Plus :size="18"/> 添加计划</button></header>
<section class="progress-panel"><div class="progress-copy"><span>OUR PROGRESS</span><strong>{{progress}}%</strong><p>已经一起完成 {{done}} 件，还有 {{items.length-done}} 件等着我们。</p></div><div class="progress-ring" :style="{'--progress':`${progress*3.6}deg`}"><div><Heart :size="20" fill="currentColor"/></div></div><div class="progress-line"><span :style="{width:`${progress}%`}"/></div></section>
<nav class="category-tabs"><button v-for="cat in categories" :key="cat.id" :class="{active:filter===cat.id}" type="button" @click="filter=cat.id"><component :is="cat.icon" :size="17"/><span>{{cat.label}}</span><small>{{cat.id==='all'?items.length:items.filter(x=>x.category===cat.id).length}}</small></button></nav>
<div v-if="listLoading" class="list-state"><LoaderCircle class="spin" :size="24"/> 正在同步共同计划</div><div v-else-if="!visible.length" class="list-state empty"><Gift :size="36"/><h3>这里还没有计划</h3><p>从一个小愿望开始，慢慢填满两个人的清单。</p><button type="button" @click="openCreate">添加第一项</button></div>
<div v-else class="items-list"><article v-for="item in visible" :key="item.id" :class="{completed:item.completed}"><button class="complete-button" type="button" :aria-label="item.completed?'标记为未完成':'标记为完成'" @click="toggleItem(item)"><Check v-if="item.completed" :size="16"/></button><span class="category-icon"><component :is="categoryMeta(item.category).icon" :size="18"/></span><div class="item-copy"><div><h3>{{item.title}}</h3><span v-if="item.priority==='high'" class="high-priority">重要</span></div><p v-if="item.note">{{item.note}}</p><footer><span>{{categoryMeta(item.category).label}}</span><span v-if="item.plannedDate"><CalendarDays :size="13"/>{{formatDate(item.plannedDate)}}</span><span v-if="item.completed" class="done-label"><Check :size="13"/> 已完成</span></footer></div><div class="item-menu"><button type="button" aria-label="更多操作" @click="menuId=menuId===item.id?null:item.id"><MoreHorizontal :size="20"/></button><div v-if="menuId===item.id"><button type="button" @click="openEdit(item)"><Edit3 :size="15"/> 编辑</button><button class="danger" type="button" @click="remove(item)"><Trash2 :size="15"/> 删除</button></div></div></article></div>
<div v-if="editorOpen" class="editor-overlay" @click.self="editorOpen=false"><section class="item-editor"><header><div><p class="eyebrow">{{editing?'EDIT PLAN':'NEW PLAN'}}</p><h2>{{editing?'编辑共同计划':'添加共同计划'}}</h2></div><button type="button" aria-label="关闭" @click="editorOpen=false"><X :size="20"/></button></header><label><span>想一起做什么？</span><input v-model="title" maxlength="100" placeholder="例如：去海边看一次日出"></label><label><span>补充说明</span><textarea v-model="note" maxlength="500" rows="3" placeholder="记录一些细节或约定"></textarea></label><div class="field-grid"><label><span>分类</span><select v-model="category"><option value="wish">愿望</option><option value="travel">旅行</option><option value="movie">电影</option><option value="date">约会</option></select></label><label><span>计划日期</span><input v-model="plannedDate" type="date"></label></div><div class="priority-field"><span>优先级</span><div><button v-for="option in [{id:'low',label:'以后再做'},{id:'normal',label:'普通'},{id:'high',label:'很想完成'}]" :key="option.id" :class="{active:priority===option.id}" type="button" @click="priority=option.id as ListPriority">{{option.label}}</button></div></div><p v-if="error" class="editor-error">{{error}}</p><footer><button type="button" @click="editorOpen=false">取消</button><button class="save" type="button" :disabled="busy" @click="save"><LoaderCircle v-if="busy" class="spin" :size="17"/><Check v-else :size="17"/>{{editing?'保存修改':'加入清单'}}</button></footer></section></div>
</section></template>
<style scoped>
.list-header h1{font-weight:800;color:#4d2c57}.list-header>button{border-radius:23px!important;background:linear-gradient(135deg,#8b4db9,#d85f99)!important;box-shadow:0 12px 26px rgba(131,63,157,.22)}.progress-panel{border:1px solid rgba(255,255,255,.8);border-radius:32px!important;background:linear-gradient(125deg,#e6caff,#ffd7e6)!important;box-shadow:0 20px 45px rgba(106,59,126,.11)}.category-tabs button{border-radius:20px!important}.category-tabs button.active{background:linear-gradient(135deg,#ecd7ff,#ffe0eb)!important}.items-list article{border-color:rgba(180,113,206,.18)!important;border-radius:25px!important;background:rgba(255,250,255,.9)!important;box-shadow:0 12px 30px rgba(95,52,114,.07)}.category-icon{border-radius:18px!important;background:linear-gradient(145deg,#ebd5ff,#ffe0eb)!important}.item-editor{border-radius:32px!important;background:linear-gradient(145deg,#fffaff,#fff4f9)!important}.item-editor input,.item-editor textarea,.item-editor select{border-radius:19px!important}.item-editor>footer .save{border-radius:21px!important;background:linear-gradient(135deg,#8b4db9,#d85f99)!important}
.list-view{width:min(100%,1000px);margin:0 auto}.list-header{display:flex;align-items:flex-end;justify-content:space-between;gap:24px;padding:14px 0 25px}.list-header h1{margin:0 0 7px;font-size:32px}.list-header>div>span{color:#89818f;font-size:13px}.list-header>button{display:flex;align-items:center;gap:8px;min-height:45px;padding:0 17px;border:0;border-radius:15px;background:#332f3a;color:#fff;font-size:11px;font-weight:750}.progress-panel{position:relative;display:flex;align-items:center;gap:26px;overflow:hidden;padding:25px 28px 30px;border-radius:23px;background:linear-gradient(125deg,#eee8f8,#faeaf0)}.progress-copy span{color:#947aae;font-size:9px;font-weight:800;letter-spacing:.13em}.progress-copy strong{display:block;margin:4px 0;font-size:30px}.progress-copy p{margin:0;color:#786f7d;font-size:11px}.progress-ring{margin-left:auto;width:67px;height:67px;padding:7px;border-radius:50%;background:conic-gradient(#aa8dd4 var(--progress),rgba(255,255,255,.6) 0)}.progress-ring div{display:grid;place-items:center;width:100%;height:100%;border-radius:50%;background:#f7f2fa;color:#d691aa}.progress-line{position:absolute;right:0;bottom:0;left:0;height:5px;background:rgba(255,255,255,.45)}.progress-line span{display:block;height:100%;background:linear-gradient(90deg,#a88bd8,#e7a6bc)}.category-tabs{display:grid;grid-template-columns:repeat(5,1fr);gap:8px;margin:20px 0 14px}.category-tabs button{display:flex;align-items:center;justify-content:center;gap:7px;min-height:45px;border:1px solid transparent;border-radius:14px;background:transparent;color:#8b8392;font-size:11px;font-weight:700}.category-tabs button.active{border-color:#e5deeb;background:#fff;color:#765ca6;box-shadow:0 8px 24px rgba(71,55,88,.05)}.category-tabs small{padding:2px 6px;border-radius:7px;background:#f0ebf5;font-size:8px}.items-list{display:grid;gap:8px}.items-list article{display:flex;align-items:center;gap:14px;padding:16px 17px;border:1px solid rgba(102,82,126,.08);border-radius:17px;background:rgba(255,255,255,.85);transition:.2s}.complete-button{display:grid;place-items:center;width:26px;height:26px;flex:0 0 26px;border:1.5px solid #cfc6d5;border-radius:9px;background:#fff;color:#fff}.category-icon{display:grid;place-items:center;width:42px;height:42px;flex:0 0 42px;border-radius:14px;background:#f0ebf7;color:#7c63a1}.item-copy{min-width:0;flex:1}.item-copy>div{display:flex;align-items:center;gap:8px}.item-copy h3{margin:0;font-size:13px}.high-priority{padding:3px 6px;border-radius:7px;background:#f9e9ef;color:#b36f87;font-size:8px;font-weight:750}.item-copy p{margin:5px 0 0;color:#8a828f;font-size:10px;overflow-wrap:anywhere}.item-copy footer{display:flex;gap:12px;margin-top:8px}.item-copy footer span{display:flex;align-items:center;gap:4px;color:#a198a7;font-size:9px}.item-copy footer .done-label{color:#6d9c80}.completed{opacity:.68}.completed .complete-button{border-color:#9f86c5;background:#9f86c5}.completed .item-copy h3{text-decoration:line-through;color:#918a97}.item-menu{position:relative}.item-menu>button{display:grid;place-items:center;width:35px;height:35px;border:0;border-radius:11px;background:transparent;color:#918897}.item-menu>div{position:absolute;z-index:3;right:0;top:38px;width:105px;padding:5px;border:1px solid #e8e1eb;border-radius:11px;background:#fff;box-shadow:0 12px 28px rgba(60,47,72,.12)}.item-menu>div button{display:flex;align-items:center;gap:7px;width:100%;padding:8px;border:0;border-radius:8px;background:transparent;font-size:10px}.item-menu .danger{color:#bd5776}.list-state{display:flex;align-items:center;justify-content:center;gap:8px;min-height:300px;color:#918999;font-size:11px}.list-state.empty{flex-direction:column}.list-state.empty svg{color:#b89fd8}.list-state h3{margin:7px 0 0;color:#403a46}.list-state p{margin:0}.list-state button{margin-top:10px;padding:10px 14px;border:0;border-radius:12px;background:#eee9f8;color:#765ca6;font-weight:700}.editor-overlay{position:fixed;z-index:60;inset:0;display:grid;place-items:center;padding:20px;background:rgba(45,39,52,.28);backdrop-filter:blur(10px)}.item-editor{width:min(100%,520px);padding:27px;border:1px solid rgba(255,255,255,.9);border-radius:24px;background:#fdfcfe}.item-editor>header{display:flex;justify-content:space-between;margin-bottom:22px}.item-editor h2{margin:0;font-size:23px}.item-editor>header button{display:grid;place-items:center;width:37px;height:37px;border:0;border-radius:12px;background:#f0ebf5}.item-editor>label,.field-grid label{display:block;margin-top:15px}.item-editor label>span,.priority-field>span{display:block;margin-bottom:8px;color:#655e6c;font-size:11px;font-weight:700}.item-editor input,.item-editor textarea,.item-editor select{width:100%;padding:13px;border:1px solid #e5dfe8;border-radius:13px;outline:0;background:#fff;font:inherit;font-size:12px}.item-editor textarea{resize:vertical}.field-grid{display:grid;grid-template-columns:1fr 1fr;gap:12px}.priority-field{margin-top:17px}.priority-field>div{display:grid;grid-template-columns:repeat(3,1fr);gap:7px}.priority-field button{min-height:39px;border:1px solid #e7e1ea;border-radius:11px;background:#fff;color:#8b8392;font-size:10px}.priority-field button.active{border-color:#b9a5d7;background:#f1ecf8;color:#745a9c}.editor-error{color:#bd5776;font-size:10px}.item-editor>footer{display:flex;justify-content:flex-end;gap:9px;margin-top:22px}.item-editor>footer button{display:flex;align-items:center;gap:7px;min-height:42px;padding:0 16px;border:0;border-radius:13px;background:#f0ebf3;font-size:11px;font-weight:700}.item-editor>footer .save{background:#332f3a;color:#fff}.spin{animation:spin 1s linear infinite}@keyframes spin{to{transform:rotate(360deg)}}
@media(max-width:650px){.list-header{align-items:flex-start}.list-header h1{font-size:26px}.list-header>div>span{font-size:11px}.list-header>button{width:44px;padding:0;justify-content:center;font-size:0}.progress-panel{padding:20px}.progress-ring{width:58px;height:58px}.category-tabs{display:flex;overflow-x:auto}.category-tabs button{min-width:84px}.items-list article{gap:10px;padding:14px 12px}.category-icon{width:37px;height:37px;flex-basis:37px}.editor-overlay{align-items:end;padding:0}.item-editor{max-height:92vh;overflow:auto;padding:22px 18px calc(22px + env(safe-area-inset-bottom));border-radius:24px 24px 0 0}.field-grid{grid-template-columns:1fr}.priority-field>div{grid-template-columns:1fr}}
</style>
